def _safe_int(val, default=0):
    """Safely convert value to int, handling NaN/NaT/None."""
    if val is None or pd.isna(val):
        return default
    try:
        return int(val)
    except (ValueError, TypeError):
        return default


def _safe_float(val, default=0.0):
    """Safely convert value to float, handling NaN/NaT/None."""
    if val is None or pd.isna(val):
        return default
    try:
        return float(val)
    except (ValueError, TypeError):
        return default


def _safe_str(val, default=""):
    """Safely convert value to string, handling NaN/NaT/None."""
    if val is None or pd.isna(val):
        return default
    return str(val)


def _get_wdc_standings(session):
    """Fetch WDC standings using fastf1 with ergast fallback."""
    year = session.event.get('EventDate').year if session.event.get('EventDate') else None
    round_num = session.event.get('RoundNumber', None)

    if not year or not round_num:
        return {}

    standings_map = {}

    # Primary: try fastf1.ergast (built-in ergast client)
    try:
        from fastf1.ergast import Ergast
        ergast = Ergast()
        standings = ergast.get_driver_standings(season=year, round=round_num)
        if standings is not None and hasattr(standings, 'content') and len(standings.content) > 0:
            df = standings.content[0]
            for _, row in df.iterrows():
                code = row.get('driverCode', '')
                pos = _safe_int(row.get('position'), 0)
                if code and pos > 0:
                    standings_map[code] = pos
            if standings_map:
                return standings_map
    except Exception as e:
        print(f"fastf1.ergast standings fetch failed: {e}")

    # Fallback: try requests to ergast API directly
    try:
        import requests
        url = f"http://ergast.com/api/f1/{year}/{round_num}/driverStandings.json"
        resp = requests.get(url, timeout=10)
        if resp.status_code == 200:
            data = resp.json()
            standings_list = data.get('MRData', {}).get('StandingsTable', {}).get('StandingsLists', [])
            if standings_list:
                for entry in standings_list[0].get('DriverStandings', []):
                    pos = _safe_int(entry.get('position'), 0)
                    driver_info = entry.get('Driver', {})
                    code = driver_info.get('code', '')
                    if code and pos > 0:
                        standings_map[code] = pos
    except Exception as e:
        print(f"Ergast API fallback failed: {e}")

    return standings_map


def get_race_results(session):
    """Extract race results for podium display."""
    results = session.results
    driver_colors = get_driver_colors(session)
    wdc_standings = _get_wdc_standings(session)

    race_data = []

    for _, row in results.iterrows():
        driver_code = _safe_str(row.get("Abbreviation"), "???")
        if pd.isna(row.get("Position")):
            continue

        position = _safe_int(row.get("Position"), 0)
        if position == 0:
            continue

        full_name = _safe_str(row.get("FullName"), driver_code)
        team = _safe_str(row.get("TeamName"), "Unknown")
        grid_pos = _safe_int(row.get("GridPosition"), 0)
        points = _safe_float(row.get("Points"), 0.0)

        # Race time - return raw seconds, let UI format
        race_time = row.get("Time")
        if pd.notna(race_time):
            race_time_secs = _safe_float(race_time.total_seconds(), None)
        else:
            race_time_secs = None

        # Status for DNF/DNS cases
        status = _safe_str(row.get("Status"), "")

        # FastestLap is a rank integer (1 = fastest lap holder)
        fastest_lap_rank = _safe_int(row.get("FastestLap"), 0)
        has_fastest_lap = (fastest_lap_rank == 1)

        # WDC position from standings lookup
        wdc_pos = wdc_standings.get(driver_code, 0)

        race_data.append({
            "code": driver_code,
            "name": full_name,
            "team": team,
            "position": position,
            "grid_pos": grid_pos,
            "race_time_secs": race_time_secs,
            "status": status,
            "points": int(points),
            "fastest_lap": has_fastest_lap,
            "wdc_position": wdc_pos,
            "color": driver_colors.get(driver_code, (128, 128, 128)),
        })

    return race_data

